package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.enumtypes.Tellerkode;
import lombok.Getter;
import lombok.Setter;

import java.math.BigDecimal;
import java.math.RoundingMode;

import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.DISPONIBILITEIT_ZONDER_BV_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeTools.isAanvullendeEuropeseVakantieDag;
import static be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeTools.isFictieveGeboorteTeller;
import static be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeTools.isOvermachtStatutair;

@Getter
@Setter
public abstract class AbstractPrestatieSamenvatting implements PrestatieSamenvatting {

    private BigDecimal tellerGewoneBezoldiging = BigDecimal.ZERO;
    private BigDecimal tellerEuropeseVakantie = BigDecimal.ZERO;
    private BigDecimal tellerZiekteEersteWeek = BigDecimal.ZERO;
    private BigDecimal tellerZiekteTweedeWeek = BigDecimal.ZERO;
    private BigDecimal tellerZiekteDerdeEnVierdeWeek = BigDecimal.ZERO;
    private BigDecimal tellerOnbezoldigd = BigDecimal.ZERO;
    private BigDecimal tellerDisponibiliteit60BV = BigDecimal.ZERO;
    private BigDecimal tellerDisponibiliteit60NBV = BigDecimal.ZERO;
    private BigDecimal tellerDisponibiliteit100 = BigDecimal.ZERO;
    private BigDecimal tellerBetaling80 = BigDecimal.ZERO;
    private BigDecimal tellerBetalingOvermacht = BigDecimal.ZERO;
    private BigDecimal tellerBetaling82 = BigDecimal.ZERO;
    private BigDecimal tellerGeboorteVerlof = BigDecimal.ZERO;
    private BigDecimal hwaarde = BigDecimal.ZERO;
    private BigDecimal werkuitkeringUren = BigDecimal.ZERO;
    private BigDecimal totaalAantalUren = BigDecimal.ZERO;
    private BigDecimal werkDagen = BigDecimal.ZERO;
    private BigDecimal theoretischeWerkDagen = BigDecimal.ZERO;
    private BigDecimal uitgeslotenUren = BigDecimal.ZERO;
    private BigDecimal langdurigeAfwezigheden = BigDecimal.ZERO;

    @Override
    public BigDecimal getTellerDisponibiliteit60() {
        return tellerDisponibiliteit60BV.add(tellerDisponibiliteit60NBV);
    }

    public void addToHwaarde(BigDecimal hwaarde) {
        this.hwaarde = this.hwaarde.add(hwaarde);
    }

    public void addToWerkuitkeringUren(BigDecimal uren) {
        this.werkuitkeringUren = this.werkuitkeringUren.add(uren);
    }

    @Override
    public BigDecimal getTotaalTeller() {
        return tellerGewoneBezoldiging.add(tellerEuropeseVakantie).add(tellerZiekteEersteWeek.add(tellerZiekteTweedeWeek.add(
                        tellerZiekteDerdeEnVierdeWeek
                                .add(tellerOnbezoldigd.add(tellerDisponibiliteit60BV.add(tellerDisponibiliteit60NBV).add(tellerDisponibiliteit100))))))
                .add(tellerBetaling80).add(tellerBetaling82).add(tellerGeboorteVerlof).add(tellerBetalingOvermacht);
    }

    protected void verwerk(BigDecimal waarde, AardKodeExtensie looncode) {
        verwerk(waarde, looncode, looncode.getTellerCode());
    }

    public void verwerk(BigDecimal waarde, AardKodeExtensie looncode, Tellerkode tellerCode) {
        switch (tellerCode) {
            case GW: // Gewone Bezoldiging
                if (isAanvullendeEuropeseVakantieDag(looncode)) {
                    tellerEuropeseVakantie = tellerEuropeseVakantie.add(waarde);
                } else {
                    tellerGewoneBezoldiging = tellerGewoneBezoldiging.add(waarde);
                }
                break;
            case Z1: //Ziekte eerste week
                tellerZiekteEersteWeek = tellerZiekteEersteWeek.add(waarde);
                break;
            case Z2: //Ziekte tweede week
                tellerZiekteTweedeWeek = tellerZiekteTweedeWeek.add(waarde);
                break;
            case Z34: //Ziekte derde en vierde week
                tellerZiekteDerdeEnVierdeWeek = tellerZiekteDerdeEnVierdeWeek.add(waarde);
                break;
            case ONB: //Onbezoldigd
                tellerOnbezoldigd = tellerOnbezoldigd.add(waarde);
                break;
            case D60: //Disponibiliteit 60 percent
                if (looncode.behoortTotGroep(DISPONIBILITEIT_ZONDER_BV_KEY)) {
                    tellerDisponibiliteit60NBV = tellerDisponibiliteit60NBV.add(waarde);
                } else {
                    tellerDisponibiliteit60BV = tellerDisponibiliteit60BV.add(waarde);
                }
                break;
            case D100: //Disponibiliteit 100 percent
                tellerDisponibiliteit100 = tellerDisponibiliteit100.add(waarde);
                break;
            case B80: //Teller 80%
                if (isOvermachtStatutair(looncode)) {
                    tellerBetalingOvermacht = tellerBetalingOvermacht.add(waarde);
                } else {
                    tellerBetaling80 = tellerBetaling80.add(waarde);
                }
                break;
            case B82: //Teller 82%
                if (isFictieveGeboorteTeller(looncode)) {
                    tellerGeboorteVerlof = tellerGeboorteVerlof.add(waarde);
                } else {
                    tellerBetaling82 = tellerBetaling82.add(waarde);
                }
                break;
            default:
                break;
        }
    }

    @Override
    public BigDecimal getTellerGewoonLoon() {
        return tellerGewoneBezoldiging.add(tellerZiekteEersteWeek);
    }

    @Override
    public BigDecimal getTellerDisponibiliteit() {
        return getTellerDisponibiliteit60().add(tellerDisponibiliteit100);
    }

    public void addToTotaalAantalUren(BigDecimal uren) {
        this.totaalAantalUren = this.totaalAantalUren.add(uren);
    }

    public void addToUitgeslotenUren(BigDecimal uren) {
        this.uitgeslotenUren = this.uitgeslotenUren.add(uren);
    }

    public void addToWerkDagen(BigDecimal werkDagen) {
        this.werkDagen = this.werkDagen.add(werkDagen);
    }

    public void addToTheoretischeWerkDagen(BigDecimal werkDagen) {
        this.theoretischeWerkDagen = this.theoretischeWerkDagen.add(werkDagen);
    }

    public void addToLangdurigeAfwezigheden(BigDecimal langdurigeAfwezigheden) {
        this.langdurigeAfwezigheden = this.langdurigeAfwezigheden.add(langdurigeAfwezigheden);
    }

    public void vermenigvuldigMetBreuk(BigDecimal teller, BigDecimal noemer) {
        setTellerGewoneBezoldiging(getTellerGewoneBezoldiging().multiply(teller).divide(noemer, RekenTools.MAX_SCALE, RoundingMode.HALF_DOWN));
        setTellerEuropeseVakantie(getTellerEuropeseVakantie().multiply(teller).divide(noemer, RekenTools.MAX_SCALE, RoundingMode.HALF_DOWN));
        setTellerZiekteEersteWeek(getTellerZiekteEersteWeek().multiply(teller).divide(noemer, RekenTools.MAX_SCALE, RoundingMode.HALF_DOWN));
        setTellerZiekteTweedeWeek(getTellerZiekteTweedeWeek().multiply(teller).divide(noemer, RekenTools.MAX_SCALE, RoundingMode.HALF_DOWN));
        setTellerZiekteDerdeEnVierdeWeek(getTellerZiekteDerdeEnVierdeWeek().multiply(teller).divide(noemer, RekenTools.MAX_SCALE, RoundingMode.HALF_DOWN));
        setTellerOnbezoldigd(getTellerOnbezoldigd().multiply(teller).divide(noemer, RekenTools.MAX_SCALE, RoundingMode.HALF_DOWN));
        setTellerDisponibiliteit60BV(getTellerDisponibiliteit60BV().multiply(teller).divide(noemer, RekenTools.MAX_SCALE, RoundingMode.HALF_DOWN));
        setTellerDisponibiliteit60NBV(getTellerDisponibiliteit60NBV().multiply(teller).divide(noemer, RekenTools.MAX_SCALE, RoundingMode.HALF_DOWN));
        setTellerBetaling80(getTellerBetaling80().multiply(teller).divide(noemer, RekenTools.MAX_SCALE, RoundingMode.HALF_DOWN));
        setTellerBetalingOvermacht(getTellerBetalingOvermacht().multiply(teller).divide(noemer, RekenTools.MAX_SCALE, RoundingMode.HALF_DOWN));
        setTellerBetaling82(getTellerBetaling82().multiply(teller).divide(noemer, RekenTools.MAX_SCALE, RoundingMode.HALF_DOWN));
        setTellerGeboorteVerlof(getTellerGeboorteVerlof().multiply(teller).divide(noemer, RekenTools.MAX_SCALE, RoundingMode.HALF_DOWN));
        setTellerDisponibiliteit100(getTellerDisponibiliteit100().multiply(teller).divide(noemer, RekenTools.MAX_SCALE, RoundingMode.HALF_DOWN));
    }

    protected <T extends AbstractPrestatieSamenvatting> T addPrestatieSamenvatting(PrestatieSamenvatting other, T samenvatting) {
        samenvatting.setTellerGewoneBezoldiging(this.getTellerGewoneBezoldiging().add(other.getTellerGewoneBezoldiging()));
        samenvatting.setTellerEuropeseVakantie(this.getTellerEuropeseVakantie().add(other.getTellerEuropeseVakantie()));
        samenvatting.setTellerZiekteEersteWeek(this.getTellerZiekteEersteWeek().add(other.getTellerZiekteEersteWeek()));
        samenvatting.setTellerZiekteTweedeWeek(this.getTellerZiekteTweedeWeek().add(other.getTellerZiekteTweedeWeek()));
        samenvatting.setTellerZiekteDerdeEnVierdeWeek(this.getTellerZiekteDerdeEnVierdeWeek().add(other.getTellerZiekteDerdeEnVierdeWeek()));
        samenvatting.setTellerOnbezoldigd(this.getTellerOnbezoldigd().add(other.getTellerOnbezoldigd()));
        samenvatting.setTellerDisponibiliteit60BV(this.getTellerDisponibiliteit60BV().add(other.getTellerDisponibiliteit60BV()));
        samenvatting.setTellerDisponibiliteit60NBV(this.getTellerDisponibiliteit60NBV().add(other.getTellerDisponibiliteit60NBV()));
        samenvatting.setTellerDisponibiliteit100(this.getTellerDisponibiliteit100().add(other.getTellerDisponibiliteit100()));
        samenvatting.setTellerBetaling80(this.getTellerBetaling80().add(other.getTellerBetaling80()));
        samenvatting.setTellerBetalingOvermacht(this.getTellerBetalingOvermacht().add(other.getTellerBetalingOvermacht()));
        samenvatting.setTellerBetaling82(this.getTellerBetaling82().add(other.getTellerBetaling82()));
        samenvatting.setTellerGeboorteVerlof(this.getTellerGeboorteVerlof().add(other.getTellerGeboorteVerlof()));
        samenvatting.setHwaarde(this.getHwaarde().add(other.getHwaarde()));
        samenvatting.setWerkuitkeringUren(this.getWerkuitkeringUren().add(other.getWerkuitkeringUren()));
        samenvatting.setTotaalAantalUren(this.getTotaalAantalUren().add(other.getTotaalAantalUren()));
        samenvatting.setWerkDagen(this.getWerkDagen().add(other.getWerkDagen()));
        return samenvatting;
    }
}
